import { enMessages } from "./en";
import { zhMessages } from "./zh";

export const messages = {
  en: enMessages,
  zh: zhMessages,
} as const;

export type Locale = keyof typeof messages;
export type Messages = typeof enMessages;
export type Namespace = keyof Messages;

/**
 * Flat translation key registry. Generated by walking namespaces so all flat
 * keys are statically known. Keeps backward compatibility with the original
 * `t(key)` API while we migrate consumers.
 */
type Flatten<TNs extends Namespace> = keyof Messages[TNs];
export type FlatKey = {
  [N in Namespace]: Flatten<N>;
}[Namespace];

type LooseMessages = Record<string, Record<string, string>>;

const FLAT_LOOKUP_EN: Record<string, string> = buildFlatLookup(enMessages as LooseMessages);
const FLAT_LOOKUP_ZH: Record<string, string> = buildFlatLookup(zhMessages as LooseMessages);

function buildFlatLookup(src: LooseMessages): Record<string, string> {
  const out: Record<string, string> = {};
  for (const ns of Object.keys(src)) {
    const bucket = src[ns];
    for (const key of Object.keys(bucket)) {
      // Last write wins, mirroring the legacy single-namespace dictionary.
      out[key] = bucket[key];
    }
  }
  return out;
}

export function flatLookup(locale: Locale): Record<string, string> {
  return locale === "zh" ? FLAT_LOOKUP_ZH : FLAT_LOOKUP_EN;
}

export function applyVariables(
  template: string,
  variables?: Record<string, string | number>,
): string {
  if (!variables) return template;
  return Object.entries(variables).reduce(
    (acc, [k, v]) => acc.replace(new RegExp(`{${k}}`, "g"), String(v)),
    template,
  );
}
